import usePost from "~/post-types__premium_only/hooks/usePost";
import { useState } from "@wordpress/element";
import useDebounce from "~/hooks/useDebounce";
import Input from "~/components/input";
import { __ } from "@wordpress/i18n";

const Search = () => {
    const { setPost, search } = usePost();
    const [searchTerm, setSearchTerm] = useState(search || "");

    useDebounce(
        () => {
            if (
                !searchTerm ||
                searchTerm.trim() === "" ||
                searchTerm.length < 2
            ) {
                if (search) setPost("search", "");
                return;
            }

            setPost("search", searchTerm);
        },
        [searchTerm],
        300,
    );

    return (
        <Input
            type="search"
            size="extrasmall"
            searchIcon
            placeholder={__("Search for Folders...", "ninja-media")}
            className="pnpnm-topbar__input"
            value={searchTerm}
            onChange={(value) => setSearchTerm(String(value))}
        />
    );
};

export default Search;
