import usePost from "~/post-types__premium_only/hooks/usePost";
import { PostMenu } from "~/types/post__premium_only/post";
import BlockStack from "~/components/blockStack";
import useSettings from "~/hooks/useSettings";
import Uncategorized from "./Uncategorized";
import Favorites from "./Favorites";
import All from "./All";
import {
    fetchPostList,
    preloadPostList,
} from "~/post-types__premium_only/utils/fetchPostList";

const Menus = () => {
    const { data } = useSettings();
    const { setPost, menu, allPosts, uncategorized, favorites } = usePost();

    const theme = data?.display?.theme?.theme ?? "default";

    const showCount = pnpnm?.settings?.general?.folder?.showCount ?? false;

    const isUncategorized =
        pnpnm?.settings?.advanced?.organization?.uncategorized ?? false;

    const isFavorites =
        pnpnm?.settings?.advanced?.organization?.favorites ?? false;

    const handleMenu = (menu: PostMenu) => {
        setPost("menu", menu);
        setPost("activeFolder", null);
        setPost("selectedFolders", []);

        const url = new URL(window.location.href);
        url.searchParams.delete("pnpnm_folder");
        url.searchParams.delete("pnpnm_uncategorized");
        url.searchParams.delete("pnpnm_favorites");

        if (menu === "uncategorized") {
            url.searchParams.set("pnpnm_uncategorized", "1");
        }
        if (menu === "favorites") {
            url.searchParams.set("pnpnm_favorites", "1");
        }

        fetchPostList(url.toString());
    };

    const buildUrl = (menu: "all" | "uncategorized" | "favorites") => {
        const url = new URL(window.location.href);
        url.searchParams.delete("pnpnm_folder");
        url.searchParams.delete("pnpnm_uncategorized");
        url.searchParams.delete("pnpnm_favorites");

        if (menu === "uncategorized") {
            url.searchParams.set("pnpnm_uncategorized", "1");
        }

        if (menu === "favorites") {
            url.searchParams.set("pnpnm_favorites", "1");
        }

        return url.toString();
    };

    return (
        <BlockStack gap={5} style={{ margin: "10px 0px" }}>
            <All
                menu={menu}
                showCount={showCount}
                count={allPosts}
                onMenu={handleMenu}
                onMouseEnter={() => preloadPostList(buildUrl("all"))}
            />

            <Uncategorized
                enabled={isUncategorized}
                menu={menu}
                showCount={showCount}
                count={uncategorized}
                onMenu={handleMenu}
                onMouseEnter={() => preloadPostList(buildUrl("uncategorized"))}
            />

            <Favorites
                enabled={isFavorites}
                menu={menu}
                theme={theme}
                showCount={showCount}
                count={favorites}
                onMenu={handleMenu}
                onMouseEnter={() => preloadPostList(buildUrl("favorites"))}
            />
        </BlockStack>
    );
};

export default Menus;
