import { useUpdatePostFolderMutation } from "~/redux/api/post__premium_only";
import { useEffect, useRef, useState } from "@wordpress/element";
import { useCustomAlert } from "~/components/alert/Alert";
import RenameFolder from "~/shared/actions/RenameFolder";
import { Theme } from "~/types/settings/settings";
import { Folder } from "~/types/folder";
import usePost from "../hooks/usePost";
import { __ } from "@wordpress/i18n";

const Rename = ({
    theme = "default",
    active,
    open,
    color,
    setCurrentFolder,
    setFolderLoading,
}: {
    theme?: Theme;
    active?: boolean;
    open?: boolean;
    color?: string | null;
    setCurrentFolder?: (folder: Folder) => void;
    setFolderLoading: (loading: boolean) => void;
}) => {
    const { setPost, renameFolder } = usePost();
    const [folderName, setFolderName] = useState<string>(
        renameFolder?.folder?.name || __("New folder", "ninja-media"),
    );
    const inputRef = useRef<HTMLInputElement | null>(null);
    const [updateFolder] = useUpdatePostFolderMutation();

    const { showAlert } = useCustomAlert();

    useEffect(() => {
        if (inputRef.current) {
            inputRef.current.focus();
            inputRef.current.select();
        }
    }, []);

    const handleRename = async () => {
        if (!renameFolder?.folder || !folderName) return;

        setFolderLoading(true);

        setPost("renameFolder", { rename: false });

        try {
            const response = await updateFolder({
                id: renameFolder?.folder?.id || "",
                name: folderName || __("New folder", "ninja-media"),
            }).unwrap();

            setCurrentFolder?.(response?.data as Folder);

            showAlert({
                toast: true,
                type: "success",
                text:
                    response?.message ||
                    __("Folder renamed successfully", "ninja-media"),
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        } catch (error: any) {
            showAlert({
                toast: true,
                type: "error",
                text:
                    error?.data?.message ||
                    __("Failed to rename folder", "ninja-media"),
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        } finally {
            setFolderLoading(false);

            setPost("renameFolder", { rename: false });
        }
    };

    return (
        <RenameFolder
            theme={theme}
            active={active}
            open={open}
            color={color}
            inputRef={inputRef}
            folderName={folderName}
            setFolderName={setFolderName}
            onRename={handleRename}
            onCancel={() => setPost("renameFolder", { rename: false })}
        />
    );
};

export default Rename;
