import { MenuItem } from "~/types/post__premium_only/post";
import { iconFolderHome } from "~/utils/icons";
import SvgIcon from "~/components/svgIcon/SvgIcon";
import Folder from "~/shared/folder/Folder";

const All = ({ menu, showCount, count, onMenu, onMouseEnter }: MenuItem) => {
    return (
        <Folder
            name="All Files"
            count={showCount ? count : undefined}
            icon={<SvgIcon src={iconFolderHome} style={{ color: menu === "all" ? "var(--pnpnm-primary)" : "#697C8B" }} />}
            active={menu === "all"}
            onClick={() => onMenu("all")}
            onMouseEnter={onMouseEnter}
        />
    );
};

export default All;
