import { ServerResponse } from "~/types/response";
import { Folder } from "~/types/folder";
import { baseApi } from "./base";
import {
    AssignPostResponse,
    CreateFolderResponse,
    GetBreadcrumbsResponse,
    GetFolderResponse,
    GetFoldersResponse,
    UpdateFolderResponse,
} from "~/types/post__premium_only/response";

export const post = baseApi.injectEndpoints({
    endpoints: (builder) => ({
        getPostFolders: builder.query<
            ServerResponse<GetFoldersResponse>,
            {
                postType: string;
                orderBy?: "name" | "size" | "createdAt" | "updatedAt";
                order?: "ASC" | "DESC";
                search?: string;
            }
        >({
            query: ({ postType, orderBy, order, search }) => {
                const params: Record<string, string> = {};

                if (orderBy) {
                    params.orderBy = orderBy;
                }
                if (order) {
                    params.order = order;
                }
                if (search) {
                    params.search = search;
                }

                return {
                    url: `post-type-library/${postType}`,
                    method: "GET",
                    params,
                };
            },

            providesTags: ["PostFolders"],
        }),

        getPostFolder: builder.query<
            ServerResponse<GetFolderResponse>,
            { postType: string; id: string | number }
        >({
            query: ({ postType, id }) => {
                return {
                    url: `post-type-library/${postType}/${id}`,
                    method: "GET",
                };
            },
        }),

        getPostBreadcrumbs: builder.query<
            ServerResponse<GetBreadcrumbsResponse>,
            { postType: string; id: string | number }
        >({
            query: ({ postType, id }) => {
                return {
                    url: `post-type-library/breadcrumbs`,
                    method: "GET",
                    params: {
                        postType,
                        id,
                    },
                };
            },
        }),

        createPostFolder: builder.mutation<
            ServerResponse<CreateFolderResponse>,
            { postType: string; name: string; parentId?: string | number }
        >({
            query: ({ postType, name, parentId }) => {
                return {
                    url: `post-type-library/folder`,
                    method: "POST",
                    body: {
                        postType,
                        name,
                        parentId,
                    },
                };
            },

            async onQueryStarted(
                { parentId },
                { dispatch, queryFulfilled, getState },
            ) {
                if (parentId) return;

                try {
                    await queryFulfilled;

                    const state = getState() as any;
                    const { folderSorting, order } = state.post;
                    const isForceSorting =
                        state.settings?.data?.general?.folder?.forceSorting ??
                        false;

                    if (!isForceSorting) return;

                    dispatch(post.util.invalidateTags(["PostFolders"]));

                    dispatch(
                        post.endpoints.getPostFolders.initiate(
                            {
                                postType: pnpnm?.currentPostType,
                                orderBy: folderSorting?.orderBy,
                                order: order,
                            },
                            { forceRefetch: true },
                        ),
                    );
                } catch {}
            },
        }),

        updatePostFolder: builder.mutation<
            ServerResponse<UpdateFolderResponse>,
            {
                id: string | number;
                name?: string;
                color?: string | null;
            }
        >({
            query: ({ id, name, color }) => {
                return {
                    url: `post-type-library/folder`,
                    method: "PUT",
                    body: {
                        id,
                        name,
                        color,
                    },
                };
            },
        }),

        copyPostFolder: builder.mutation<
            ServerResponse<{ folders: Folder[] }>,
            { parentId: string | number; id: string | number }
        >({
            query: ({ parentId, id }) => {
                return {
                    url: `post-type-library/folder/copy`,
                    method: "POST",
                    body: {
                        parentId,
                        ids: [id],
                    },
                };
            },
        }),

        movePostFolder: builder.mutation<
            ServerResponse<null>,
            { id: string | number; ids: (string | number)[] }
        >({
            query: ({ id, ids }) => {
                return {
                    url: `post-type-library/folder/move`,
                    method: "POST",
                    body: {
                        parentId: id,
                        ids,
                    },
                };
            },
        }),

        deletePostFolder: builder.mutation<
            ServerResponse<{ allPosts: number; uncategorized: number }>,
            { ids: (string | number)[] }
        >({
            query: ({ ids }) => {
                return {
                    url: `post-type-library/folder`,
                    method: "DELETE",
                    body: {
                        ids,
                    },
                };
            },
        }),

        assignPost: builder.mutation<
            ServerResponse<AssignPostResponse>,
            { id: string | number; posts: (string | number)[] }
        >({
            query: ({ id, posts }) => {
                return {
                    url: `post-type-library/folder/${id}/assign`,
                    method: "POST",
                    body: {
                        posts,
                    },
                };
            },
        }),

        favoritePost: builder.mutation<
            ServerResponse<{
                favorites: number;
            }>,
            { postType: string; ids: (string | number)[]; favorite: boolean }
        >({
            query: ({ postType, ids, favorite }) => {
                return {
                    url: `post-type-library/favorite`,
                    method: "POST",
                    body: {
                        postType,
                        ids,
                        favorite,
                    },
                };
            },
        }),
    }),
});

export const {
    useGetPostFoldersQuery,
    useLazyGetPostFolderQuery,
    useGetPostBreadcrumbsQuery,
    useCreatePostFolderMutation,
    useUpdatePostFolderMutation,
    useCopyPostFolderMutation,
    useMovePostFolderMutation,
    useDeletePostFolderMutation,
    useAssignPostMutation,
    useFavoritePostMutation,
} = post;
