import { useAppDispatch, useAppSelector } from "~/redux/hooks";
import { PostState } from "~/types/post__premium_only/states";
import { NestedKey, NestedValue } from "~/utils/types";
import { useCallback } from "@wordpress/element";
import {
    selectPost,
    updatePost,
} from "~/redux/features/post__premium_only/post";

const usePost = () => {
    const post = useAppSelector(selectPost);

    const dispatch = useAppDispatch();

    const setPost = useCallback(
        <Path extends NestedKey<PostState>>(
            path: Path,
            value: NestedValue<PostState, Path>,
        ) => {
            dispatch(updatePost({ path, value }));
        },
        [],
    );

    return { ...post, setPost };
};

export default usePost;
